VkDevice device = VK_NULL_HANDLE;
VkSwapchainKHR swapchain = VK_NULL_HANDLE;
VkLatencySleepInfoNV sleepInfo = {};
sleepInfo.sType = VK_STRUCTURE_TYPE_LATENCY_SLEEP_INFO_NV;

VkResult result = vkLatencySleepNV(
    device,
    swapchain,
    &sleepInfo
);

if (result == VK_SUCCESS) {
    // تمت العملية بنجاح ويمكن متابعة العمل بعد vkLatencySleepNV
} else {
    // عالج رمز الخطأ أو أعد تهيئة الموارد المطلوبة
}
